  ...currentItem
};

const CAMPOS_PERMITIDOS = ["url_image", "user_medical_info_id"];

return $input.all().map((item) => {

  let body = item.json.body ?? item.json;

  // ================================
  // 1. Se vier como string, parseia
  // ================================
  if (typeof body === "string") {
    body = body.trim().replace(/}}+$/, "}");

    try {
      body = JSON.parse(body);
    } catch (e) {
      return {
        json: {
          success: false,
          status: 400,
          error: {
            code: "INVALID_JSON",
            message: "Body não é um JSON válido",
            received: body
          }
        }
      };
    }
  }

  // ==========================================
  // 2. Sanitiza valores string (multipart bug)
  // ==========================================
  for (const key in body) {
    if (typeof body[key] === "string") {
      body[key] = body[key].trim().replace(/}}+$/, "");
    }
  }

  // ================================
  // 3. Campos desconhecidos
  // ================================
  const camposEnviados = Object.keys(body);
  const camposInvalidos = camposEnviados.filter(
    (c) => !CAMPOS_PERMITIDOS.includes(c)
  );

  if (camposInvalidos.length > 0) {
    return {
      json: {
        success: false,
        status: 400,
        error: {
          code: "INVALID_FIELD",
          message: "Campo(s) não reconhecido(s) no payload",
          invalid_fields: camposInvalidos,
          allowed_fields: CAMPOS_PERMITIDOS
        }
      }
    };
  }

  // ================================
  // 4. url_image obrigatório
  // ================================
  if (!body.url_image) {
    return {
      json: {
        success: false,
        status: 400,
        error: {
          code: "MISSING_FIELD",
          message: "O campo 'url_image' é obrigatório",
          example: {
            url_image: "https://site.com/image.png",
            user_medical_info_id: 123
          }
        }
      }
    };
  }

  // ================================
  // 5. user_medical_info_id obrigatório
  // ================================
  if (body.user_medical_info_id === undefined) {
    return {
      json: {
        success: false,
        status: 400,
        error: {
          code: "MISSING_FIELD",
          message: "O campo 'user_medical_info_id' é obrigatório"
        }
      }
    };
  }

  // ================================
  // 6. Tipagem do ID
  // ================================
  const id = body.user_medical_info_id;

  if (
    !(
      typeof id === "number" ||
      (typeof id === "string" && /^\d+$/.test(id))
    )
  ) {
    return {
      json: {
        success: false,
        status: 400,
        error: {
          code: "INVALID_TYPE",
          message: "'user_medical_info_id' deve ser número ou string numérica",
          received: id
        }
      }
    };
  }

  // ================================
  // ✅ SUCESSO
  // ================================
  return {
    json: {
      success: true,
      status: 200,
      data: {
        url_image: body.url_image,
        user_medical_info_id: Number(id)
      }
    }
  };
});

/**
 * CLIENT-SPECIFIC SCORING — Simple Validator (Standalone)
 * Minimal conceptual alignment fixes:
 * 1) Requirement: OU (carimbo + assinatura) OU (QR Code validado).
 * 2) "Assinatura Digital" check should NOT be treated as inconsistency when physical path (carimbo+assinatura) is valid.
 * 3) Same weight for both paths (OR gate) applied in scoring.
 * 4) Remove double counting: QR/carimbo issues no longer hard-fail dataConsistency.
 * 5) Score always clamped 0..100.
 *
 * n8n input source:
 *   const raw = $('API SADM').first().json.inputRaw;
 */

// ---------------- helpers ----------------
function get(obj, path, fallback = null) {
  try {
    const parts = path.split(".");
    let cur = obj;
    for (const p of parts) {
      if (cur == null) return fallback;
      cur = cur[p];
    }
    return cur === undefined ? fallback : cur;
  } catch {
    return fallback;
  }
}

function clamp(n, a, b) {
  const x = Number.isFinite(n) ? n : 0;
  return Math.max(a, Math.min(b, x));
}

function isTrue(v) { return v === true; }

function pickCrmUF(input) {
  return (
    get(input, "medical_professional.cfm_data.cfm_data.crm_state", "") ||
    get(input, "medical_professional.crm_state", "") ||
    ""
  );
}

// ---------------- input normalization ----------------
const raw = $('API SADM').first().json.inputRaw;
const input = Array.isArray(raw) ? (raw[0] ?? {}) : (raw ?? {});

const webhookId =
  $('Webhook').first().json.body?.user_medical_info_id ?? null;

const userMedicalInfoId =
  webhookId ??
  get(input, "user_medical_info_id", null) ??
  get(input, "document_metadata.user_medical_info_id", null) ??
  null;

const docType = get(input, "document_metadata.document_type", "");
const isMedCert = isTrue(get(input, "document_metadata.is_medical_certificate", false));

const ocrConf = Number(get(input, "ocr.confidence_avg", 0));
const matchScore = Number(get(input, "ocr.match_score", 0));
const mismatchFields = get(input, "ocr.mismatch_fields", []);
const ocrHasMismatch = Array.isArray(mismatchFields) && mismatchFields.length > 0;

const patientName = get(input, "patient_identification.patient_name", "");

const cid = get(input, "medical_classification.cid_parent", "");
const cidFound = get(input, "medical_classification.cid_oms_data.cid_found", null);

const leaveDays = Number(get(input, "attendance_information.leave.days", 0));
const leaveRisk = get(input, "attendance_information.leave.leave_days_risk", "");

const attendanceDateStatus = get(input, "attendance_information.attendance_date_status", "");
const captureType = get(input, "capture.capture_type", "");

const crmNumber = get(input, "medical_professional.crm_number", "");
const crmUF = pickCrmUF(input);
const crmSituation = get(input, "medical_professional.cfm_data.cfm_data.situation", "");
const crmMatchStatus = get(input, "medical_professional.cfm_data.cfm_data.match_status", "");
const crmMatchScore = Number(get(input, "medical_professional.cfm_data.cfm_data.match_score", 0));

const hasStamp = isTrue(get(input, "document_elements.has_stamp", false));
const stampValid = isTrue(get(input, "document_elements.stamp_valid", false));

// IMPORTANT: "carimbo com assinatura" requires BOTH stamp + handwritten signature
const hasHandSignature = isTrue(get(input, "document_elements.has_signature", false));
const handSignatureValid = isTrue(get(input, "document_elements.signature_valid", false));

const hasMandatoryFields = isTrue(get(input, "document_elements.has_mandatory_fields", false));
const hasDoctorData = isTrue(get(input, "document_elements.has_doctor_data", false));
const hasPatientData = isTrue(get(input, "document_elements.has_patient_data", false));
const hasAttendanceData = isTrue(get(input, "document_elements.has_attendance_data", false));

const manipulationDetected = isTrue(get(input, "manipulation_analysis.detected", false));
const digitalManip = get(input, "forensic_analysis.digital_manipulation_indicators", "none");
const physicalManip = get(input, "forensic_analysis.physical_manipulation_indicators", "none");
const aiIndicators = get(input, "forensic_analysis.ai_generation_or_reconstruction_indicators", "none");
const anyVisualIssue = (() => {
  const vq = get(input, "forensic_analysis.visual_quality_issues", {});
  if (!vq || typeof vq !== "object") return false;
  return Object.values(vq).some(x => x === true);
})();

const imgConsistency = Number(get(input, "image_scores.consistency", 1));
const imgCompleteness = Number(get(input, "image_scores.completeness", 1));
const imgQuality = Number(get(input, "image_scores.image_quality", 1));

// QR (client uses as "Assinatura Digital")
const qrExists = isTrue(get(input, "qr_validation.qr_code_data.qr_exists", false));
const qrDecodable = isTrue(get(input, "qr_validation.qr_code_data.qr_decodable", false));
const qrUrlStatus = get(input, "qr_validation.qr_code_data.qr_url_status", "");
const qrIsValid = (qrExists && qrDecodable && qrUrlStatus === "active");

// ---------------- check status mapping (client) ----------------

// Carimbo check == "carimbo + assinatura" (physical authenticity path)
function stampStatus() {
  if (!hasStamp) return "FAIL";
  // PASS only if stamp is valid AND handwritten signature is present+valid
  if (hasStamp && stampValid && hasHandSignature && handSignatureValid) return "PASS";
  // stamp present but missing/invalid signature or stamp issues => WARN
  return "WARN";
}

// "Assinatura Digital" (QR) should NOT be considered an inconsistency when the physical path is PASS.
// Minimal and pragmatic: if physical path is PASS => treat as PASS (not required).
function signatureStatus(stpSt) {
  if (stpSt === "PASS") return "PASS"; // QR not required when carimbo+assinatura pass
  if (!qrExists) return "FAIL";
  if (qrIsValid) return "PASS";
  return "FAIL";
}

// OR gate: OU (carimbo+assinatura) OU (QR válido)
// - PASS if either path is PASS
// - WARN if none PASS but at least one WARN
// - FAIL if both FAIL
function sealOrQrStatus(sigSt, stpSt) {
  if (sigSt === "PASS" || stpSt === "PASS") return "PASS";
  if (sigSt === "WARN" || stpSt === "WARN") return "WARN";
  return "FAIL";
}

function dataConsistencyStatus(sealOrQrSt) {
  const crmOk = (String(crmSituation).toLowerCase() === "active") && (String(crmMatchStatus).toLowerCase() === "matched");
  const cidOk = (cid !== "" && cidFound === true);
  const imgOk = (imgConsistency >= 0.9 && imgCompleteness >= 0.9 && imgQuality >= 0.9);
  const ocrOk = (ocrConf >= 0.95 && !ocrHasMismatch && matchScore >= 0.95);
  const temporalOk = (attendanceDateStatus === "within_deadline" || attendanceDateStatus === "" || attendanceDateStatus === "unknown");

  // Remove double counting:
  const hardFail =
    manipulationDetected ||
    digitalManip === "strong" || physicalManip === "strong" ||
    aiIndicators === "confirmed" || aiIndicators === "likely" ||
    !hasMandatoryFields ||
    !hasDoctorData || !hasPatientData || !hasAttendanceData;

  if (hardFail) return "FAIL";

  const softWarn =
    (sealOrQrSt !== "PASS") ||
    !crmOk ||
    !cidOk ||
    !imgOk ||
    !ocrOk ||
    !temporalOk ||
    (leaveDays >= 10) ||
    (String(leaveRisk).toLowerCase() === "high" || String(leaveRisk).toLowerCase() === "very_high") ||
    (captureType === "scan") ||
    anyVisualIssue ||
    (digitalManip !== "none" || physicalManip !== "none" || aiIndicators !== "none");

  if (softWarn) return "WARN";
  return "PASS";
}

// ---------------- compute statuses (ORDER MATTERS) ----------------
const stpSt = stampStatus();                 // physical path: carimbo + assinatura
const sigSt = signatureStatus(stpSt);        // QR path, but PASS if physical path already PASS
const sealQrSt = sealOrQrStatus(sigSt, stpSt);
const datSt = dataConsistencyStatus(sealQrSt);

// ---------------- scoring (0..100) ----------------
let score = 9;

// Document-type sanity
if (!isMedCert || docType !== "medical_certificate") score += 85;

// Apply penalties only on the OR result (avoid penalizing both independently)
if (sealQrSt === "FAIL") score += 40;
if (sealQrSt === "WARN") score += 18;

if (datSt === "FAIL") score += 45;
if (datSt === "WARN") score += 20;

// Additional signals (simple)
if (String(crmSituation).toLowerCase() !== "active") score += 30;
if (String(crmMatchStatus).toLowerCase() !== "matched") score += 20;
if (Number.isFinite(crmMatchScore) && crmMatchScore > 0 && crmMatchScore < 0.35) score += 10;

if (cid === "") score += 10;
if (cidFound === false) score += 25;

if (ocrConf > 0 && ocrConf < 0.90) score += 18;
else if (ocrConf > 0 && ocrConf < 0.95) score += 8;

if (ocrHasMismatch) score += 12;

if (leaveDays >= 15) score += 18;
else if (leaveDays >= 10) score += 12;
else if (leaveDays >= 6) score += 6;

if (manipulationDetected) score += 35;
if (digitalManip !== "none") score += (digitalManip === "weak" ? 8 : digitalManip === "moderate" ? 18 : 28);
if (physicalManip !== "none") score += (physicalManip === "weak" ? 6 : physicalManip === "moderate" ? 14 : 22);
if (aiIndicators !== "none") score += (aiIndicators === "suspected" ? 12 : aiIndicators === "likely" ? 22 : 30);

if (anyVisualIssue) score += 10;

// clamp
score = clamp(Math.round(score), 0, 100);

// ---------------- risk level bands (client UI) ----------------
const riskLevel =
  score >= 80 ? "HIGH" :
  score >= 50 ? "MEDIUM" :
  "LOW";

// ---------------- copy-safe text builders (deterministic) ----------------
function buildHeadline(risk) {
  if (risk === "HIGH") return "Possível fraude detectada pela IA";
  return "Verificação manual recomendada";
}

function buildSummary(risk) {
  if (risk === "HIGH") return "Inconsistências significativas nos dados do documento.";
  return "Documento validado com atenção. Alguns detalhes requerem verificação manual.";
}

function buildTags(risk, scoreValue, checksArr) {
  if (risk === "LOW") return ["Baixo Risco"];
  if (risk === "MEDIUM") {
    const att = checksArr.filter(c => c.status !== "PASS").length;
    return [`Risco Moderado`, `${att} pontos de atenção`];
  }
  const probs = checksArr.filter(c => c.status === "FAIL").length + (scoreValue >= 90 ? 2 : 0);
  return ["Risco Alto", `${Math.max(1, probs)} problemas graves`];
}

